import { LitElement, css, html } from 'lit';
import { customElement, state } from 'lit/decorators.js';

import '@shoelace-style/shoelace/dist/components/card/card.js';
import '@shoelace-style/shoelace/dist/components/button/button.js';
import '@shoelace-style/shoelace/dist/components/icon/icon.js';

import { styles } from '../styles/shared-styles';

@customElement('app-home')
export class AppHome extends LitElement {

  // @state sprawia, że komponent odświeży się automatycznie, gdy pojawi się sygnał do instalacji
  @state() private deferredPrompt: any = null;

  static styles = [
    styles,
    css`
    main {
      padding: 16px;
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
      gap: 20px;
    }

    sl-card {
      width: 100%;
      max-width: 400px;
    }

    .install-section {
      margin-top: 24px;
      padding: 20px;
      border-top: 1px solid var(--sl-color-neutral-200);
      width: 100%;
    }

    .ios-info {
      font-size: 0.85em;
      color: var(--sl-color-neutral-600);
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
    }
  `];

  constructor() {
    super();
    // Nasłuchiwanie sygnału instalacji (Android/Windows)
    window.addEventListener('beforeinstallprompt', (e) => {
      e.preventDefault();
      this.deferredPrompt = e;
    });

    // Ukrywamy przycisk po udanej instalacji
    window.addEventListener('appinstalled', () => {
      this.deferredPrompt = null;
    });
  }

  async installApp() {
    if (!this.deferredPrompt) return;
    
    this.deferredPrompt.prompt();
    const { outcome } = await this.deferredPrompt.userChoice;
    
    if (outcome === 'accepted') {
      this.deferredPrompt = null;
    }
  }

  render() {
    return html`
      <main>
        <h1>Witaj w aplikacji mParafia</h1>
        <p>Twoja parafia jest teraz zawsze z Tobą, nawet bez zasięgu.</p>
        
        <sl-card>
          Możesz sprawdzić, że ta aplikacja działa całkowicie <strong>offline</strong>! 
          Wyłącz Wi-Fi i przekonaj się sama.
        </sl-card>

        <div class="install-section">
          ${this.deferredPrompt ? html`
            <!-- Przycisk dla Androida i Windowsa -->
            <sl-button variant="primary" pill @click="${this.installApp}">
              <sl-icon slot="prefix" name="download"></sl-icon>
              Zainstaluj aplikację mParafia
            </sl-button>
          ` : html`
            <!-- Informacja dla iPhone / użytkowników z zainstalowaną apką -->
            <div class="ios-info">
              <span>Jeśli chcesz mieć ikonkę na pulpicie:</span>
              <br>
              <strong>Safari: kliknij Udostępnij <sl-icon name="share"></sl-icon> i "Do ekranu początkowego"</strong>
            </div>
          `}
        </div>
      </main>
    `;
  }
}

